transform_js:
transformedData = {
  regions: [],
  productTypes: [],
  seriesData: []
};

if (rawData && rawData.rows) {
  const regions = rawData.rows.map(row => row.region);
  transformedData.regions = regions;

  const firstRow = rawData.rows[0];
  const productTypes = Object.keys(firstRow).filter(key => key !== 'region');
  transformedData.productTypes = productTypes;

  productTypes.forEach(productType => {
    const data = rawData.rows.map(row => row[productType]);
    transformedData.seriesData.push({
      name: productType,
      type: 'bar',
      data: data,
      coordinateSystem: 'polar',
      stack: 'total',
      emphasis: {
        focus: 'series'
      }
    });
  });
}

echarts_js:
option = {
  title: {
    text: post.title,
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    formatter: (params) => {
      return params.name + '<br/>' + params.seriesName + ': ' + params.value;
    }
  },
  legend: {
    data: transformedData.productTypes,
    bottom: 0
  },
  angleAxis: {
    type: 'category',
    data: transformedData.regions,
    startAngle: 90
  },
  radiusAxis: {
    min: 0
  },
  polar: {},
  series: transformedData.seriesData
};
